questionvariables.text:
/* V1: Series RLC Natural Response, Underdamped */
R_val: 10;
L_val: 0.01;
C_val: 0.0001;
Vs_val: 20;
t1: 0.001;

/* Damping parameters */
alpha_val: R_val/(2*L_val);
omega0_val: 1/sqrt(L_val*C_val);
omega_d: sqrt(omega0_val^2 - alpha_val^2);

/* Wrong alpha (other topology formula) for error detection */
alpha_wrong: 1/(2*R_val*C_val);

/* Regime classification MCQ */
regime_opts: random_permutation([[1, true, "Underdamped"], [2, false, "Overdamped"], [3, false, "Critically damped"]]);

/* Response at t1 */
val_at_t1: float((Vs_val/(omega_d*L_val))*exp(-alpha_val*t1)*sin(omega_d*t1));

/* Debug MCQ-MA */
debug_opts: random_permutation([[1, true, "The initial value i(0+) is wrong; it should be 0 for a fully charged capacitor"], [2, true, "The decay envelope uses the wrong time constant (too slow)"], [3, false, "The oscillation frequency does not match the damped frequency omega_d"], [4, false, "The final value should approach a nonzero DC level"], [5, false, "The waveform should not oscillate because the circuit is overdamped"]]);
correct_errors: {1,2};

/* Teacher answers */
ta_alpha: float(alpha_val);
ta_omega0: float(omega0_val);
ta_regime: regime_opts;
ta_value: val_at_t1;
ta_debug: correct_errors;

/* V2: Parallel RLC Step Response, Overdamped */
R_val: 20;
L_val: 0.1;
C_val: 1e-05;
Is_val: 0.1;
t1: 0.0005;

/* Damping parameters */
alpha_val: 1/(2*R_val*C_val);
omega0_val: 1/sqrt(L_val*C_val);
omega_d: 0;  /* overdamped — no oscillation */

/* Wrong alpha (other topology formula) for error detection */
alpha_wrong: R_val/(2*L_val);

/* Regime classification MCQ */
regime_opts: random_permutation([[1, true, "Overdamped"], [2, false, "Underdamped"], [3, false, "Critically damped"]]);

/* Response at t1 */
disc: sqrt(alpha_val^2 - omega0_val^2);
s1: -alpha_val + disc;
s2: -alpha_val - disc;
A1: Is_val/(C_val*(s1 - s2));
A2: -A1;
val_at_t1: float(A1*exp(s1*t1) + A2*exp(s2*t1));

/* Debug MCQ-MA */
debug_opts: random_permutation([[1, false, "The initial value v(0+) = 0 is correct"], [2, true, "The waveform should NOT oscillate because the circuit is overdamped"], [3, true, "The final value v(infinity) should be 0, not I_s*R"], [4, false, "The damping coefficient alpha was computed with the wrong formula"], [5, false, "The waveform should start at a nonzero value"]]);
correct_errors: {2,3};

/* Teacher answers */
ta_alpha: float(alpha_val);
ta_omega0: float(omega0_val);
ta_regime: regime_opts;
ta_value: val_at_t1;
ta_debug: correct_errors;

/* V3: Series RLC Step Response, Critically Damped */
R_val: 200;
L_val: 0.1;
C_val: 1e-05;
Vs_val: 10;
t1: 0.002;

/* Damping parameters */
alpha_val: R_val/(2*L_val);
omega0_val: 1/sqrt(L_val*C_val);
omega_d: 0;  /* critically damped */

/* Wrong alpha (other topology formula) for error detection */
alpha_wrong: 1/(2*R_val*C_val);

/* Regime classification MCQ */
regime_opts: random_permutation([[1, true, "Critically damped"], [2, false, "Underdamped"], [3, false, "Overdamped"]]);

/* Response at t1 */
val_at_t1: float(Vs_val*(1 - (1 + alpha_val*t1)*exp(-alpha_val*t1)));

/* Debug MCQ-MA */
debug_opts: random_permutation([[1, true, "The initial value v_C(0+) should be 0, not V_s"], [2, true, "A critically damped response does NOT overshoot; the plot is wrong"], [3, false, "The final value v_C(infinity) = V_s is correct for a step response"], [4, false, "The time constant is wrong; it should be 1/alpha = 1 ms"], [5, false, "The circuit is actually underdamped, not critically damped"]]);
correct_errors: {1,2};

/* Teacher answers */
ta_alpha: float(alpha_val);
ta_omega0: float(omega0_val);
ta_regime: regime_opts;
ta_value: val_at_t1;
ta_debug: correct_errors;

/* V4: Parallel RLC Natural Response, Underdamped */
R_val: 100;
L_val: 0.05;
C_val: 5e-06;
V0_val: 15;
t1: 0.0005;

/* Damping parameters */
alpha_val: 1/(2*R_val*C_val);
omega0_val: 1/sqrt(L_val*C_val);
omega_d: sqrt(omega0_val^2 - alpha_val^2);

/* Wrong alpha (other topology formula) for error detection */
alpha_wrong: R_val/(2*L_val);

/* Regime classification MCQ */
regime_opts: random_permutation([[1, true, "Underdamped"], [2, false, "Overdamped"], [3, false, "Critically damped"]]);

/* Response at t1 */
omega_d: sqrt(omega0_val^2 - alpha_val^2);
val_at_t1: float(V0_val*exp(-alpha_val*t1)*(cos(omega_d*t1) + (alpha_val/omega_d)*sin(omega_d*t1)));

/* Debug MCQ-MA */
debug_opts: random_permutation([[1, false, "The initial value v(0+) = V_0 is correct"], [2, true, "The decay envelope uses omega_0 instead of alpha for the time constant"], [3, true, "The oscillation frequency should be omega_d, not omega_0"], [4, false, "The final value should be nonzero"], [5, false, "The waveform should be a pure exponential (no oscillation)"]]);
correct_errors: {2,3};

/* Teacher answers */
ta_alpha: float(alpha_val);
ta_omega0: float(omega0_val);
ta_regime: regime_opts;
ta_value: val_at_t1;
ta_debug: correct_errors;
